const express = require('express');
const session = require('express-session');
const Twilio = require('twilio');

const app = express();
app.use(express.json());
app.use(express.urlencoded({ extended: false }));

app.use(
  session({
    secret: process.env.SESSION_SECRET || 'change_this_secret_in_production',
    resave: false,
    saveUninitialized: false,
    cookie: {
      httpOnly: true,
      sameSite: 'lax',
      secure: process.env.NODE_ENV === 'production'
    }
  })
);

const twilioClient =
  process.env.TWILIO_ACCOUNT_SID && process.env.TWILIO_AUTH_TOKEN
    ? Twilio(process.env.TWILIO_ACCOUNT_SID, process.env.TWILIO_AUTH_TOKEN)
    : null;

const TWILIO_FROM = process.env.TWILIO_FROM_NUMBER || '';
const OTP_TTL_MS = 5 * 60 * 1000;
const RESEND_COOLDOWN_MS = 30 * 1000;
const MAX_ATTEMPTS = 5;

const pendingOtps = new Map();

function generateOtp() {
  return String(Math.floor(100000 + Math.random() * 900000));
}

function normalizePhone(phone) {
  return String(phone || '').replace(/[^\d+]/g, '');
}

function storeOtp(sessionId, phone, code) {
  pendingOtps.set(sessionId, {
    phone,
    code,
    attempts: 0,
    expiresAt: Date.now() + OTP_TTL_MS,
    lastSentAt: Date.now()
  });
}

function getOtpRecord(sessionId) {
  const record = pendingOtps.get(sessionId);
  if (!record) return null;
  if (Date.now() > record.expiresAt) {
    pendingOtps.delete(sessionId);
    return null;
  }
  return record;
}

async function sendSms(to, body) {
  if (!twilioClient) {
    console.log(`[SMS MOCK] To: ${to} | Message: ${body}`);
    return;
  }
  if (!TWILIO_FROM) throw new Error('TWILIO_FROM_NUMBER is not configured');
  await twilioClient.messages.create({
    to,
    from: TWILIO_FROM,
    body
  });
}

app.post('/auth/2fa/request', async (req, res) => {
  try {
    if (!req.session) return res.status(500).json({ error: 'Session unavailable' });

    const phone = normalizePhone(req.body.phone);
    if (!phone) return res.status(400).json({ error: 'Phone number is required' });

    const existing = getOtpRecord(req.session.id);
    if (existing && Date.now() - existing.lastSentAt < RESEND_COOLDOWN_MS) {
      return res.status(429).json({ error: 'Please wait before requesting another code' });
    }

    const code = generateOtp();
    storeOtp(req.session.id, phone, code);

    await sendSms(
      phone,
      `Your verification code is ${code}. It expires in 5 minutes. If you did not request this, ignore this message.`
    );

    req.session.pending2fa = true;
    req.session.pendingPhone = phone;

    return res.json({ success: true, message: 'Verification code sent' });
  } catch (error) {
    return res.status(500).json({ error: 'Failed to send verification code' });
  }
});

app.post('/auth/2fa/verify', (req, res) => {
  try {
    if (!req.session) return res.status(500).json({ error: 'Session unavailable' });

    const code = String(req.body.code || '').trim();
    if (!/^\d{6}$/.test(code)) {
      return res.status(400).json({ error: 'A valid 6-digit code is required' });
    }

    const record = getOtpRecord(req.session.id);
    if (!record) {
      return res.status(400).json({ error: 'Code expired or not found' });
    }

    if (record.attempts >= MAX_ATTEMPTS) {
      pendingOtps.delete(req.session.id);
      return res.status(429).json({ error: 'Too many failed attempts' });
    }

    if (record.code !== code) {
      record.attempts += 1;
      return res.status(401).json({ error: 'Invalid verification code' });
    }

    pendingOtps.delete(req.session.id);
    req.session.isTwoFactorVerified = true;
    req.session.pending2fa = false;
    req.session.pendingPhone = record.phone;

    return res.json({ success: true, message: 'Two-factor authentication verified' });
  } catch (error) {
    return res.status(500).json({ error: 'Verification failed' });
  }
});

function require2fa(req, res, next) {
  if (req.session && req.session.isTwoFactorVerified) return next();
  return res.status(401).json({ error: 'Two-factor authentication required' });
}

app.get('/protected', require2fa, (req, res) => {
  res.json({ success: true, message: 'Protected content accessible' });
});

app.post('/auth/logout', (req, res) => {
  if (req.session) {
    pendingOtps.delete(req.session.id);
    req.session.destroy(() => {});
  }
  res.json({ success: true });
});

app.get('/', (req, res) => {
  res.json({
    success: true,
    routes: {
      request2fa: 'POST /auth/2fa/request',
      verify2fa: 'POST /auth/2fa/verify',
      protected: 'GET /protected'
    }
  });
});

